<?php
require_once __DIR__ . '/helpers.php';
require_once __DIR__ . '/erp_migrations.php';
require_login();
erp_run_phase1_migrations($pdo);
$userId = (int) $_SESSION['user_id'];
$user = current_user($pdo) ?: [];
$isAdmin = is_admin($pdo, $userId);
$profile = (string) ($user['access_profile'] ?? 'Utilizador');
if (!erp_user_can($pdo, $user, 'erp.view')) { http_response_code(403); exit('Acesso reservado ao ERP.'); }

function erp_count(PDO $pdo, string $sql): int { return (int) $pdo->query($sql)->fetchColumn(); }
function erp_money(float $value): string { return number_format($value, 2, ',', '.') . ' €'; }
function erp_page_url(string $page): string { return 'erp.php?page=' . urlencode($page); }

$flashSuccess = $flashError = null;
if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    if (!validate_csrf_or_abort(false)) { $flashError = 'Pedido inválido. Atualize a página e tente novamente.'; }
    else {
        $action = trim((string)($_POST['action'] ?? ''));
        try {
            $pdo->beginTransaction();
            if ($action === 'create_customer' && erp_user_can($pdo, $user, 'erp.customers')) {
                $stmt = $pdo->prepare('INSERT INTO erp_customers(code, name, tax_number, country, address, phone, email, discount_percent, is_active) VALUES (?,?,?,?,?,?,?,?,1)');
                $data = [trim($_POST['code'] ?? ''), trim($_POST['name'] ?? ''), trim($_POST['tax_number'] ?? ''), trim($_POST['country'] ?? 'Portugal'), trim($_POST['address'] ?? ''), trim($_POST['phone'] ?? ''), trim($_POST['email'] ?? ''), (float)($_POST['discount_percent'] ?? 0)];
                $stmt->execute($data); erp_audit($pdo, $userId, 'create', 'erp_customers', (int)$pdo->lastInsertId(), [], ['code'=>$data[0], 'name'=>$data[1]]); $flashSuccess = 'Cliente criado.';
            } elseif ($action === 'create_supplier' && erp_user_can($pdo, $user, 'erp.suppliers')) {
                $stmt = $pdo->prepare('INSERT INTO erp_suppliers(code, name, tax_number, country, address, phone, email, is_active) VALUES (?,?,?,?,?,?,?,1)');
                $data = [trim($_POST['code'] ?? ''), trim($_POST['name'] ?? ''), trim($_POST['tax_number'] ?? ''), trim($_POST['country'] ?? 'Portugal'), trim($_POST['address'] ?? ''), trim($_POST['phone'] ?? ''), trim($_POST['email'] ?? '')];
                $stmt->execute($data); erp_audit($pdo, $userId, 'create', 'erp_suppliers', (int)$pdo->lastInsertId(), [], ['code'=>$data[0], 'name'=>$data[1]]); $flashSuccess = 'Fornecedor criado.';
            } elseif ($action === 'create_raw_material' && erp_user_can($pdo, $user, 'erp.master_data')) {
                $stmt = $pdo->prepare('INSERT INTO erp_raw_materials(code, description, material_type_id, material_feature_id, width, grammage, primary_unit_id, min_stock, reorder_point, preferred_supplier_id, standard_price, status, notes, created_by, updated_by) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)');
                $data = [trim($_POST['code'] ?? ''), trim($_POST['description'] ?? ''), (int)($_POST['material_type_id'] ?? 0) ?: null, (int)($_POST['material_feature_id'] ?? 0) ?: null, (float)($_POST['width'] ?? 0), (float)($_POST['grammage'] ?? 0), (int)($_POST['primary_unit_id'] ?? 0) ?: null, (float)($_POST['min_stock'] ?? 0), (float)($_POST['reorder_point'] ?? 0), (int)($_POST['preferred_supplier_id'] ?? 0) ?: null, (float)($_POST['standard_price'] ?? 0), trim($_POST['status'] ?? 'Ativo'), trim($_POST['notes'] ?? ''), $userId, $userId];
                $stmt->execute($data); erp_audit($pdo, $userId, 'create', 'erp_raw_materials', (int)$pdo->lastInsertId(), [], ['code'=>$data[0], 'description'=>$data[1]]); $flashSuccess = 'Matéria-prima criada.';
            } elseif ($action === 'create_finished_product' && erp_user_can($pdo, $user, 'erp.master_data')) {
                $stmt = $pdo->prepare('INSERT INTO erp_finished_products(code, customer_product_code, customer_id, product_type_id, material_type_id, material_feature_id, width, length, grammage, colors_per_face, description, unit_id, min_stock, proof_reference, proof_status, sale_price, standard_cost, status, notes, created_by, updated_by) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)');
                $data = [trim($_POST['code'] ?? ''), trim($_POST['customer_product_code'] ?? ''), (int)($_POST['customer_id'] ?? 0) ?: null, (int)($_POST['product_type_id'] ?? 0) ?: null, (int)($_POST['material_type_id'] ?? 0) ?: null, (int)($_POST['material_feature_id'] ?? 0) ?: null, (float)($_POST['width'] ?? 0), (float)($_POST['length'] ?? 0), (float)($_POST['grammage'] ?? 0), (int)($_POST['colors_per_face'] ?? 0), trim($_POST['description'] ?? ''), (int)($_POST['unit_id'] ?? 0) ?: null, (float)($_POST['min_stock'] ?? 0), trim($_POST['proof_reference'] ?? ''), trim($_POST['proof_status'] ?? 'Pendente'), (float)($_POST['sale_price'] ?? 0), (float)($_POST['standard_cost'] ?? 0), trim($_POST['status'] ?? 'Ativo'), trim($_POST['notes'] ?? ''), $userId, $userId];
                $stmt->execute($data); erp_audit($pdo, $userId, 'create', 'erp_finished_products', (int)$pdo->lastInsertId(), [], ['code'=>$data[0], 'description'=>$data[10]]); $flashSuccess = 'Produto acabado criado.';
            } elseif ($action === 'create_product' && $isAdmin) {
                $stmt=$pdo->prepare('INSERT INTO erp_products(code, description, unit_id, unit_cost, unit_price, min_stock) VALUES (?,?,?,?,?,?)');
                $data=[trim($_POST['code']??''), trim($_POST['description']??''), (int)($_POST['unit_id']??0) ?: null, (float)($_POST['unit_cost']??0), (float)($_POST['unit_price']??0), (float)($_POST['min_stock']??0)];
                $stmt->execute($data); erp_audit($pdo, $userId, 'create_legacy', 'erp_products', (int)$pdo->lastInsertId(), [], ['code'=>$data[0], 'description'=>$data[1]]); $flashSuccess='Artigo legado criado.';
            } elseif ($action === 'create_order' && $isAdmin) {
                $stmt=$pdo->prepare('INSERT INTO erp_production_orders(order_number, product_id, planned_quantity, due_date, notes, estimated_material_cost, estimated_labor_cost, estimated_overhead_cost, created_by) VALUES (?,?,?,?,?,?,?,?,?)');
                $stmt->execute([trim($_POST['order_number']??''), (int)($_POST['product_id']??0), (float)($_POST['planned_quantity']??0), trim($_POST['due_date']??'') ?: null, trim($_POST['notes']??'') ?: null, (float)($_POST['estimated_material_cost']??0), (float)($_POST['estimated_labor_cost']??0), (float)($_POST['estimated_overhead_cost']??0), $userId]);
                $of=(int)$pdo->lastInsertId(); $op=$pdo->query('SELECT id FROM erp_operations ORDER BY id LIMIT 1')->fetchColumn();
                if ($op) $pdo->prepare('INSERT INTO erp_production_order_operations(production_order_id, operation_id, sequence_no, planned_minutes) VALUES (?,?,10,0)')->execute([$of,(int)$op]);
                erp_audit($pdo, $userId, 'create_legacy', 'erp_production_orders', $of, [], ['order_number'=>trim($_POST['order_number']??'')]); $flashSuccess='OF criada.';
            } elseif ($action === 'create_document' && $isAdmin) {
                $stmt=$pdo->prepare('INSERT INTO erp_production_order_documents(production_order_id, title, document_url, body, is_required, created_by) VALUES (?,?,?,?,?,?)');
                $stmt->execute([(int)($_POST['production_order_id']??0), trim($_POST['title']??''), trim($_POST['document_url']??'') ?: null, trim($_POST['body']??'') ?: null, (int)($_POST['is_required']??0), $userId]);
                erp_audit($pdo, $userId, 'create_legacy', 'erp_production_order_documents', (int)$pdo->lastInsertId(), [], ['title'=>trim($_POST['title']??'')]); $flashSuccess='Documento anexado à OF.';
            } elseif ($action === 'stock_adjust' && erp_user_can($pdo, $user, 'erp.stock_adjust')) {
                $qty=(float)($_POST['quantity']??0); if ($qty == 0.0) { throw new RuntimeException('A quantidade não pode ser zero.'); }
                $allowNegative = $pdo->query("SELECT value FROM erp_settings WHERE key='allow_negative_stock'")->fetchColumn() === '1';
                if ($qty < 0 && !$allowNegative) { throw new RuntimeException('Stock negativo não permitido. Use reversão ou autorização administrativa.'); }
                $number = 'MOV-' . date('YmdHis') . '-' . $userId;
                $stmt=$pdo->prepare('INSERT INTO erp_stock_movements(movement_number,movement_type,item_type,item_id,quantity,weight,warehouse_to_id,location_to_id,unit_cost,total_cost,reason,notes,created_by) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)');
                $stmt->execute([$number, $qty > 0 ? 'Ajuste positivo' : 'Ajuste negativo', $_POST['item_type'], (int)$_POST['item_id'], $qty, (float)($_POST['weight']??0), (int)($_POST['warehouse_id']??0) ?: null, (int)($_POST['location_id']??0) ?: null, (float)($_POST['unit_cost']??0), $qty*(float)($_POST['unit_cost']??0), trim($_POST['reason']??''), trim($_POST['notes']??''), $userId]);
                erp_audit($pdo, $userId, 'stock_adjust', 'erp_stock_movements', (int)$pdo->lastInsertId(), [], ['movement_number'=>$number,'quantity'=>$qty], trim($_POST['reason']??'')); $flashSuccess = 'Movimento registado no ledger.';
            } else { throw new RuntimeException('Sem permissão ou ação desconhecida.'); }
            $pdo->commit();
        } catch (Throwable $e) { if ($pdo->inTransaction()) $pdo->rollBack(); $flashError = 'Erro: ' . $e->getMessage(); }
    }
}

$page = (string)($_GET['page'] ?? 'overview');
$units=$pdo->query('SELECT * FROM erp_units ORDER BY code')->fetchAll(PDO::FETCH_ASSOC);
$materialTypes=$pdo->query('SELECT * FROM erp_material_types ORDER BY code')->fetchAll(PDO::FETCH_ASSOC);
$features=$pdo->query('SELECT * FROM erp_material_features ORDER BY code')->fetchAll(PDO::FETCH_ASSOC);
$productTypes=$pdo->query('SELECT * FROM erp_product_types ORDER BY code')->fetchAll(PDO::FETCH_ASSOC);
$customers=$pdo->query('SELECT * FROM erp_customers ORDER BY id DESC LIMIT 100')->fetchAll(PDO::FETCH_ASSOC);
$suppliers=$pdo->query('SELECT * FROM erp_suppliers ORDER BY id DESC LIMIT 100')->fetchAll(PDO::FETCH_ASSOC);
$rawMaterials=$pdo->query('SELECT rm.*, mt.name material_type, mf.description feature_name FROM erp_raw_materials rm LEFT JOIN erp_material_types mt ON mt.id=rm.material_type_id LEFT JOIN erp_material_features mf ON mf.id=rm.material_feature_id ORDER BY rm.id DESC LIMIT 100')->fetchAll(PDO::FETCH_ASSOC);
$finishedProducts=$pdo->query('SELECT fp.*, c.name customer_name FROM erp_finished_products fp LEFT JOIN erp_customers c ON c.id=fp.customer_id ORDER BY fp.id DESC LIMIT 100')->fetchAll(PDO::FETCH_ASSOC);
$products=$pdo->query('SELECT p.*, u.code unit_code FROM erp_products p LEFT JOIN erp_units u ON u.id=p.unit_id ORDER BY p.id DESC LIMIT 50')->fetchAll(PDO::FETCH_ASSOC);
$warehouses=$pdo->query('SELECT * FROM erp_warehouses ORDER BY code')->fetchAll(PDO::FETCH_ASSOC);
$locations=$pdo->query('SELECT l.*, w.code warehouse_code FROM erp_locations l JOIN erp_warehouses w ON w.id=l.warehouse_id ORDER BY w.code,l.code')->fetchAll(PDO::FETCH_ASSOC);
$recentMovements=$pdo->query('SELECT * FROM erp_stock_movements ORDER BY id DESC LIMIT 20')->fetchAll(PDO::FETCH_ASSOC);
$legacyOrders=$pdo->query('SELECT o.*, p.code product_code FROM erp_production_orders o JOIN erp_products p ON p.id=o.product_id ORDER BY o.id DESC LIMIT 20')->fetchAll(PDO::FETCH_ASSOC);

$erpNav = [
    'overview'=>['Visão geral'], 'sales'=>['Comercial','Orçamentos','Encomendas de clientes','Confirmações de encomenda','Clientes'], 'purchases'=>['Compras','Encomendas a fornecedores','Encomendas pendentes','Receções','Fornecedores'], 'production'=>['Planeamento e produção','Ordens de fabrico','Planeamento','Registos de produção','Consumos','Produções concluídas'], 'warehouse'=>['Armazém','Existências','Bobinas e lotes','Movimentos','Transferências','Inventários','Reservas'], 'shipping'=>['Expedição','Preparação','Expedições','Histórico'], 'quality'=>['Qualidade','Não conformidades','Anomalias','Medidas corretivas'], 'costs'=>['Custos','Custos estimados','Custos reais','Margens'], 'reports'=>['Relatórios'], 'master'=>['Dados mestre'], 'settings'=>['Configuração ERP']
];
